content.content:
[
  {
    "id": "S1",
    "description": "Link-substrate field and type rename sweep: type→label, semanticMeaning→kind, MeaningDoc→KindDoc, MeaningEntry→KindEntry, listMeanings()→listKinds(), linkMeanings→linkKinds (kit field and consumes).",
    "rationale": "Brief names these as a coordinated rename to match the vocabulary landing in this commission (kind = load-bearing identity, label = casual text).",
    "included": true
  },
  {
    "id": "S2",
    "description": "Plugin-namespaced id separator sweep from ':' to '.' for qualified identifiers (link kinds, roles, event patterns, rig templates). Permissions stay on ':' (distinct grammar).",
    "rationale": "Brief calls out the separator unification so qualified ids read consistently across the guild; click c-mo34644p prescribes the replacement.",
    "included": true
  },
  {
    "id": "S3",
    "description": "CLI tool surface update: writ-link --kind flag and rename writ-link-meanings → writ-link-kinds (tool name, HTTP route, instructions text, docstrings).",
    "rationale": "The rename propagates to operator-visible command and flag names; the tool server exposes the tool by its route, so the shift is user-facing.",
    "included": true
  },
  {
    "id": "S4",
    "description": "Oculus writ-page adds a kind dropdown to the inline add-link form, populated from listKinds(); label stays as free-text with existing datalist autocomplete.",
    "rationale": "The brief explicitly adds a kind control on the writ page so link kinds can be set from the UI rather than CLI-only.",
    "included": true
  },
  {
    "id": "S5",
    "description": "Per-plugin status convention on writs: top-level status slot keyed by pluginId (K8s-style), last-writer-wins per key, persists across terminal states, plugin-owned shape (unknown/untyped for v1).",
    "rationale": "Brief establishes this as a guild-wide convention and lands the first slot (spider) in this commission; concluded clicks (c-mo33dxf5, c-mo33duvq, c-mo33dyln, c-mo33dz7m, c-mo33e065, c-mo33e1vs) pre-decide its semantics.",
    "included": true
  },
  {
    "id": "S6",
    "description": "Spider registers the spider.follows link kind via supportKit.linkKinds with a human-readable description; Clerk consumes it through the existing kit substrate.",
    "rationale": "First real consumer of link kinds; without registration the ingest/validation pipeline rejects writes.",
    "included": true
  },
  {
    "id": "S7",
    "description": "Spider dispatch gating: in trySpawn(), consult each candidate writ's spider.follows dependencies and conjunctively require all targets to be in a terminal state before spawning a rig.",
    "rationale": "The core feature — without this, spider.follows carries no behavior.",
    "included": true
  },
  {
    "id": "S8",
    "description": "Stuck cascade on failed blocker: when any spider.follows target is in a failed terminal state, transition the dependent writ from open to stuck with a human-readable resolution and status.spider.stuckCause='failed-blocker'.",
    "rationale": "Brief prescribes cascade behavior and structured provenance so recovery flows can distinguish spider-authored stucks from engine-authored ones.",
    "included": true
  },
  {
    "id": "S9",
    "description": "Cycle detection: when evaluating a candidate writ, walk the spider.follows graph and if a cycle is detected, mark all cycle participants stuck with status.spider.stuckCause='cycle' and a human-readable resolution.",
    "rationale": "Brief names cycles as a distinct failure mode with its own stuckCause value.",
    "included": true
  },
  {
    "id": "S10",
    "description": "Auto-unstick on blocker recovery: each poll, Spider scans stuck writs whose status.spider.stuckCause is set, re-evaluates their spider.follows graph, and transitions stuck→open (clearing the cause) when the stuck condition no longer holds.",
    "rationale": "Brief prescribes auto-recovery so that operator-driven or out-of-band unblocking flows don't require manual unstick.",
    "included": true
  },
  {
    "id": "S11",
    "description": "Documentation updates: Spider README/arch-doc for gating and status.spider slot; Clerk README/arch-doc for label/kind/listKinds/KindDoc; any prose docs referencing colon-form link-kind ids.",
    "rationale": "Brief lists prose doc surfaces as in-scope for the sweep, and the new Spider semantics need narrative coverage.",
    "included": true
  }
]

