[
  {
    "id": "D1",
    "scope": [
      "S5"
    ],
    "question": "How is the name collision between the existing WritDoc.status (lifecycle phase, WritStatus) and the new per-plugin status slot (Record<PluginId, unknown>) resolved on writs?",
    "context": "WritDoc today has a top-level field named `status` of type WritStatus ('new'|'open'|'stuck'|'completed'|'failed'|'cancelled'). The brief and click c-mo33duvq describe the new per-plugin slot as being literally named `status`, referenced as `status.spider.stuckCause`. Both names cannot coexist as-is. The concluded clicks specify last-writer-wins per plugin key, implicit default of {}, and CDC emission through the normal mutation path — they assume a shape, but they don't name the field.",
    "options": {
      "a-rename-new-slot": "Pick a different name for the new slot (e.g. `pluginStatus`, `observers`, `extensions`). Leave WritDoc.status untouched as the lifecycle phase. Example becomes `pluginStatus.spider.stuckCause`. Minimal blast radius — only new code touches the new field.",
      "b-rename-existing-phase": "Rename the existing WritDoc.status to WritDoc.phase (or similar). Free up `status` for the new slot shape. Large blast radius: every clerk/spider/page/test read of `writ.status === 'open'` updates to `writ.phase`. Matches brief/click literal naming.",
      "c-k8s-restructure": "Restructure WritDoc.status to be the Record<PluginId, unknown> itself, with the lifecycle phase promoted into `status.phase` (K8s-style). `writ.status.phase === 'open'`, `writ.status.spider.stuckCause === '...'`. Deepest blast radius but the most faithful K8s analogy; adds nested-field filtering concerns to WritFilters.",
      "d-scope-by-convention": "Keep WritDoc.status as WritStatus, but establish that the *convention* (the new K8s-style slot) is written as a sibling field named something else on a per-apparatus basis (e.g. the spider slot is WritDoc.spiderStatus). Loses the uniform Record<PluginId, unknown> shape the brief describes but avoids any rename."
    },
    "recommendation": "a-rename-new-slot",
    "rationale": "Minimal blast radius, preserves the one-shot 'in-place rename' assumption the brief endorses elsewhere, and keeps WritFilters/CDC/transition machinery untouched. The name variance from the brief's literal wording is small enough to resolve in the spec; the shape (Record<PluginId, unknown>) is preserved."
  },
  {
    "id": "D2",
    "scope": [
      "S2"
    ],
    "question": "Does the composite-id internal separator in WritLinkDoc ({sourceId}:{targetId}:{normalizedType}) change from ':' to '.' as part of the separator sweep?",
    "context": "The WritLinkDoc composite primary key is constructed as `${sourceId}:${targetId}:${normalizedType}` in clerk.ts:441. This is a tuple delimiter inside a Stacks book key, not a plugin-namespaced identifier. The sweep's scope per click c-mo34644p is 'link meanings, role contributions, event/standing-order patterns, and similar qualified-name use cases'.",
    "options": {
      "a-keep-colon": "Leave the composite-id separator as ':'. It is a structural tuple delimiter with no cross-plugin visibility; the sweep target is namespaced identifiers, not primary-key formats.",
      "b-change-to-dot": "Rewrite the composite-id construction to use '.'. Requires a one-shot migration of existing WritLinkDoc keys."
    },
    "recommendation": "a-keep-colon",
    "rationale": "Three Defaults do not apply; the composite-id separator is a Stacks key tuple delimiter not a qualified id. Razor does not match (no cross-component reach — the format is internal to Clerk). Extending the sweep here would force a data migration for no consumer benefit.",
    "selected": "a-keep-colon"
  },
  {
    "id": "D3",
    "scope": [
      "S7"
    ],
    "question": "When Spider evaluates a candidate writ for dispatch, does it read links via the writ's outbound spider.follows edges (the candidate is the source), or the targets' inbound spider.follows edges (the candidate reaches forward)?",
    "context": "In spider.follows semantics, source → target means 'source depends on target'. So a writ's *own* dependencies are its outbound spider.follows edges. The brief uses the phrasing 'inbound links of a load-bearing kind' but this is reversed framing — 'inbound on the target' and 'outbound on the source' are the same edges, just indexed differently. clerk.links(writId) returns both {outbound, inbound}.",
    "options": {
      "a-outbound": "Read clerk.links(candidate).outbound and filter kind === 'spider.follows'. Each result row is a writ-the-candidate-depends-on; check its lifecycle status.",
      "b-inbound": "Read clerk.links(candidate).inbound and filter kind === 'spider.follows'. Semantic mismatch — these are writs that depend on the candidate, not writs the candidate depends on."
    },
    "recommendation": "a-outbound",
    "rationale": "Outbound matches the directional semantics ('I depend on these targets'). Option b would require inverting the meaning of spider.follows at the read site, introducing confusion. Razor does not apply (internal implementation detail with no cross-component reach); Three Defaults favor the reading that matches stated directionality.",
    "selected": "a-outbound"
  },
  {
    "id": "D4",
    "scope": [
      "S8",
      "S10"
    ],
    "question": "Does Spider write status.spider.stuckCause on every stuck transition it causes, or does it also tag engine-cascade stucks so absence-of-cause uniquely means 'not Spider's'?",
    "context": "Today the engine-cascade stuck path (spider.ts:2192-2199) transitions writ→stuck with just a resolution string. The brief introduces status.spider.stuckCause with values 'failed-blocker' | 'cycle'. Auto-unstick must distinguish Spider-authored stucks (auto-recoverable) from engine-authored stucks (not auto-recoverable without intervention).",
    "options": {
      "a-only-spider-gating": "status.spider.stuckCause is written only on failed-blocker and cycle stucks. Engine-cascade stucks leave status.spider untouched. Auto-unstick scan ignores stucks where the cause is absent.",
      "b-tag-everything": "Engine-cascade stucks also write status.spider.stuckCause (e.g. 'engine-failure'). Auto-unstick scan filters by specific values ('failed-blocker' | 'cycle')."
    },
    "recommendation": "a-only-spider-gating",
    "rationale": "Matches brief's literal enumeration ('failed-blocker' | 'cycle'). Absence of cause is a simpler signal than presence of a specific value. The engine-cascade path stays unchanged, keeping its blast radius minimal. Razor does not apply (internal Spider logic).",
    "selected": "a-only-spider-gating"
  },
  {
    "id": "D5",
    "scope": [
      "S8",
      "S9"
    ],
    "question": "How does Spider treat a spider.follows blocker that ended in the 'cancelled' terminal state (as opposed to 'completed' or 'failed')?",
    "context": "Terminal writ states are {'completed', 'failed', 'cancelled'}. The brief says 'held until targets reach a terminal state' (all three release the gate) AND 'if a blocker fails, cascade stuck' (failed triggers cascade). 'Cancelled' is an operator-driven terminal state — the writ didn't complete its work, but also didn't fail. The brief does not name cancelled explicitly.",
    "options": {
      "a-release-like-completed": "Cancelled blocker releases the gate like completed. The dependent writ becomes dispatchable. Interpretation: cancellation is an intentional operator action; downstream work is assumed still desired.",
      "b-cascade-like-failed": "Cancelled blocker cascades stuck like failed. status.spider.stuckCause='failed-blocker'. Interpretation: the blocker did not complete its work, so the dependent is presumed compromised.",
      "c-separate-cause": "Cancelled blocker cascades stuck with a distinct cause value ('cancelled-blocker'). Gives operators more precise observability."
    },
    "recommendation": "a-release-like-completed",
    "rationale": "Cancellation is operator-driven and intentional; if the operator wanted to block dependents, they'd keep the blocker stuck or transition it to failed. Treating cancelled as release-like-completed preserves operator agency. The cascade-stuck interpretation in the brief reads most naturally as 'the terminal state signals failure, not the absence of completion'. Razor: not a match — this is a semantic detail internal to one kind, with no cross-component reach. Auto-decide.",
    "selected": "a-release-like-completed"
  },
  {
    "id": "D6",
    "scope": [
      "S8",
      "S9"
    ],
    "question": "What fields go in status.spider beyond stuckCause?",
    "context": "The brief's example is 'status.spider.stuckCause'. No other fields are named. Parked click c-mo301yp9 (visibility gap on open/waiting/running) and c-mo33e194 (typed status contributions) both defer richer observability. v1 has the narrow goal of distinguishing Spider-authored stucks from others.",
    "options": {
      "a-minimal": "Just { stuckCause: 'failed-blocker' | 'cycle' }. No additional context fields.",
      "b-with-blockers": "{ stuckCause, blockers: string[] } — for failed-blocker, list the failing target writ ids; for cycle, list the cycle participants. Aids debugging without committing to typed schema.",
      "c-rich": "Include timestamps, last-evaluated-at, retry counters, etc. (More than the brief asks for.)"
    },
    "recommendation": "a-minimal",
    "rationale": "Parked clicks explicitly scope richer observability to future commissions. Minimal v1 shape means the first consumer of the convention establishes it with the lightest footprint, leaving room to extend without breaking consumers. Human-readable resolution text already carries the blocker/cycle details; structured duplication can wait. Razor: not a match (internal-to-Spider shape, no cross-component read). Auto-decide.",
    "selected": "a-minimal"
  },
  {
    "id": "D7",
    "scope": [
      "S7",
      "S10"
    ],
    "question": "Are dispatch-gating and auto-unstick performed in a single scan (widen trySpawn's query to include stuck writs with status.spider set) or two separate scans per poll?",
    "context": "trySpawn() today queries status='open' writs for dispatch. Auto-unstick needs to re-evaluate stuck writs where Spider owns the cause. One option widens the query; the other keeps them as two distinct passes.",
    "options": {
      "a-two-scans": "Keep trySpawn()'s open-writ query unchanged. Add a second scan per crawl tick for stuck writs (filtered in-memory to those with status.spider.stuckCause). Each pass has a clear single responsibility.",
